import React from 'react';
import './index.css';
import Image from './phonk_wallpaper.jpg';
import {Link} from "react-router-dom";

let flag = false

function LastNews() {
  return (
    <div>
      <p>За послденее время...</p>
    </div>
  )
}

const MainPage = () => {
    return(
      <div id="content">
        <Link to="news">
          <div id="news">
            <p class="name_card">Новости</p>
            <div id="news_place">
              <LastNews />
            </div>
          </div>
        </Link>
        <Link to="/shop" id="second_blocks">
          <div id="game_shop" class="game_item_shop_card">
            <p class="name_card">Магазин</p>
            <img src={Image} alt="Хаха"/>
          </div>
        </Link>
        <Link to="/item" id="second_blocks">
          <div id="item_store" class="game_item_shop_card">
            <p class="name_card">Торговая площадка</p>
            <img src={Image} alt="Хаха"></img>
          </div>
        </Link>
      </div>
    )
}
  

export default MainPage;
